import type { BrowserSupport } from 'frontend-device_detection';
import type { NordicRenderingContextFlags } from '../../common/types';

export type IIFEScriptName =
  | 'n-img-blur'
  | 'n-img-fallback'
  | 'n-img-handler'
  | 'n-img-lazy'
  | 'n-islands-core'
  | 'n-islands-visible'
  | 'n-safe-area';

export function createIIFEScriptsStore(
  flags: NordicRenderingContextFlags,
  support: BrowserSupport,
) {
  const entries: Array<[IIFEScriptName, string]> = [
    ['n-safe-area', '@nordic/safe-area/dist/iife/index.js'],
    ['n-img-blur', '@nordic/image/dist/iife/blur.js'],
    ['n-img-fallback', '@nordic/image/dist/iife/fallback.js'],
    ['n-img-lazy', '@nordic/image/dist/iife/lazy.js'],
    [
      'n-img-handler',
      `@nordic/image/dist/iife/handler${support.customElements.builtIn ? '' : '-polyfill'}.js`,
    ],
  ];

  if (flags.islands) {
    entries.push(
      ['n-islands-core', '@nordic/islands/dist/iife/core.js'],
      ['n-islands-visible', '@nordic/islands/dist/iife/visible.js'],
    );
  }

  return new Map(entries);
}
